import React, { useState, useRef, useMemo, useCallback, useEffect } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

function sigmoid(x) {
  const cx = Math.max(-500, Math.min(500, x));
  return 1 / (1 + Math.exp(-cx));
}
function swish(x) { return x * sigmoid(x); }

const D = 4;
const dimColors = ['#38bdf8', '#f472b6', '#fbbf24', '#a3e635'];
const dimLabels = ['A', 'B', 'C', 'D'];

const presets = [
  { name: 'Mixed', x1: [2.0, -1.5, 0.8, 3.0], x2: [3.0, -4.0, 0.2, 1.5] },
  { name: 'All Blocked', x1: [2.0, -1.5, 0.8, 3.0], x2: [-5.5, -5.0, -4.5, -5.8] },
  { name: 'All Open', x1: [2.0, -1.5, 0.8, 3.0], x2: [4.0, 3.5, 5.0, 4.5] },
  { name: 'Near Zero', x1: [2.0, -1.5, 0.8, 3.0], x2: [-0.3, 0.1, -0.1, 0.3] },
];

const W = 560, H = 195;
const pad = { top: 18, bottom: 28, left: 42, right: 18 };
const chartW = W - pad.left - pad.right;
const chartH = H - pad.top - pad.bottom;
const xMin = -6, xMax = 6;
const yMin = -1.2, yMax = 6;

const xToSvg = x => pad.left + (x - xMin) / (xMax - xMin) * chartW;
const yToSvg = y => pad.top + (1 - (y - yMin) / (yMax - yMin)) * chartH;
const svgToX = sx => xMin + (sx - pad.left) / chartW * (xMax - xMin);

export default function App() {
  const [x1, setX1] = useState([2.0, -1.5, 0.8, 3.0]);
  const [x2, setX2] = useState([3.0, -4.0, 0.2, 1.5]);
  const [dragging, setDragging] = useState(null);
  const [hovered, setHovered] = useState(null);
  const svgRef = useRef(null);

  const curvePath = useMemo(() => {
    const pts = [];
    for (let i = 0; i <= 300; i++) {
      const x = xMin + (xMax - xMin) * i / 300;
      pts.push((i === 0 ? 'M' : 'L') + xToSvg(x).toFixed(1) + ',' + yToSvg(swish(x)).toFixed(1));
    }
    return pts.join('');
  }, []);

  const results = useMemo(() => {
    return x1.map((v1, i) => {
      const v2 = x2[i];
      const sig = sigmoid(v2);
      const sw = swish(v2);
      const out = v1 * sw;
      return {
        x1: v1, x2: v2,
        sigmoid: Math.round(sig * 10000) / 10000,
        swish: Math.round(sw * 10000) / 10000,
        output: Math.round(out * 10000) / 10000,
      };
    });
  }, [x1, x2]);

  const getSvgCoords = useCallback((e) => {
    const svg = svgRef.current;
    if (!svg) return null;
    const rect = svg.getBoundingClientRect();
    const clientX = e.touches ? e.touches[0].clientX : e.clientX;
    return (clientX - rect.left) / rect.width * W;
  }, []);

  const handleMove = useCallback((e) => {
    if (dragging === null) return;
    e.preventDefault();
    const sx = getSvgCoords(e);
    if (sx === null) return;
    const newX = Math.round(Math.max(xMin + 0.1, Math.min(xMax - 0.1, svgToX(sx))) * 10) / 10;
    setX2(prev => prev.map((v, i) => i === dragging ? newX : v));
  }, [dragging, getSvgCoords]);

  const handleUp = useCallback(() => { setDragging(null); }, []);

  useEffect(() => {
    if (dragging !== null) {
      window.addEventListener('mousemove', handleMove);
      window.addEventListener('mouseup', handleUp);
      window.addEventListener('touchmove', handleMove, { passive: false });
      window.addEventListener('touchend', handleUp);
      return () => {
        window.removeEventListener('mousemove', handleMove);
        window.removeEventListener('mouseup', handleUp);
        window.removeEventListener('touchmove', handleMove);
        window.removeEventListener('touchend', handleUp);
      };
    }
  }, [dragging, handleMove, handleUp]);

  const applyPreset = (p) => { setX1([...p.x1]); setX2([...p.x2]); };

  const allBlocked = x2.every(v => v < -3);
  const allOpen = x2.every(v => v > 2.5);
  const nearZero = x2.every(v => Math.abs(v) < 1);
  const activeIdx = hovered !== null ? hovered : (dragging !== null ? dragging : null);

  const maxAbsOut = Math.max(...results.map(r => Math.abs(r.output)), 0.1);
  const maxAbsSw = Math.max(...results.map(r => Math.abs(r.swish)), 0.1);

  const getGatePercent = (sw) => {
    const maxGate = Math.max(...results.map(r => Math.abs(r.swish)), 0.01);
    return Math.min(100, Math.abs(sw) / Math.max(maxGate, 0.5) * 100);
  };

  return (
    <div style={{
      background: theme.colors.background, minHeight: '100vh',
      fontFamily: theme.font, color: theme.colors.text,
      display: 'flex', flexDirection: 'column', alignItems: 'center',
      padding: '12px 16px',
    }}>
      <div style={{ width: '100%', maxWidth: 600 }}>
        {/* Title */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 8 }}>
          <div style={{ fontSize: 17, fontWeight: 700, color: theme.colors.text }}>
            SwiGLU Activation
          </div>
          <div style={{ display: 'flex', gap: 5 }}>
            {presets.map(p => (
              <button key={p.name} onClick={() => applyPreset(p)} style={{
                background: theme.colors.surfaceAlt, border: '1px solid ' + theme.colors.border,
                color: theme.colors.textSecondary, borderRadius: 4, padding: '3px 8px',
                fontSize: 10, cursor: 'pointer', fontFamily: theme.font,
              }}>{p.name}</button>
            ))}
          </div>
        </div>

        {/* Subtitle */}
        <div style={{ fontSize: 11, color: theme.colors.textSecondary, marginBottom: 8 }}>
          Drag the colored dots on the Swish curve to control each gate
        </div>

        {/* Swish Curve SVG */}
        <div style={{ background: theme.colors.surface, borderRadius: 8, padding: '6px 4px', marginBottom: 8 }}>
          <svg ref={svgRef} viewBox={`0 0 ${W} ${H}`} width="100%" style={{ display: 'block', cursor: dragging !== null ? 'grabbing' : 'default' }}>
            {/* Grid lines */}
            {[-4, -2, 0, 2, 4].map(x => (
              <line key={'gx' + x} x1={xToSvg(x)} x2={xToSvg(x)} y1={pad.top} y2={H - pad.bottom}
                stroke={theme.colors.border} strokeWidth={x === 0 ? 1.2 : 0.5} />
            ))}
            {[0, 2, 4].map(y => (
              <line key={'gy' + y} x1={pad.left} x2={W - pad.right} y1={yToSvg(y)} y2={yToSvg(y)}
                stroke={theme.colors.border} strokeWidth={y === 0 ? 1.2 : 0.5} />
            ))}
            {/* Axis labels */}
            {[-4, -2, 0, 2, 4].map(x => (
              <text key={'lx' + x} x={xToSvg(x)} y={H - pad.bottom + 15}
                textAnchor="middle" fontSize={9} fill={theme.colors.textMuted}>{x}</text>
            ))}
            {[0, 2, 4].map(y => (
              <text key={'ly' + y} x={pad.left - 8} y={yToSvg(y) + 3}
                textAnchor="end" fontSize={9} fill={theme.colors.textMuted}>{y}</text>
            ))}
            <text x={W / 2} y={H - 2} textAnchor="middle" fontSize={9} fill={theme.colors.textMuted}>x2</text>
            <text x={8} y={H / 2} textAnchor="middle" fontSize={9} fill={theme.colors.textMuted}
              transform={`rotate(-90, 8, ${H / 2})`}>Swish(x2)</text>

            {/* Swish curve */}
            <path d={curvePath} fill="none" stroke={theme.colors.primary} strokeWidth={2} opacity={0.6} />

            {/* Projection lines from dots to axis */}
            {x2.map((v, i) => {
              const sw = swish(v);
              const cx = xToSvg(v);
              const cy = yToSvg(sw);
              const isActive = activeIdx === i;
              return (
                <g key={'proj' + i} opacity={isActive ? 0.7 : 0.25}>
                  <line x1={cx} x2={cx} y1={cy} y2={yToSvg(0)} stroke={dimColors[i]} strokeWidth={1} strokeDasharray="3,3" />
                  <line x1={cx} x2={xToSvg(0)} y1={cy} y2={cy} stroke={dimColors[i]} strokeWidth={1} strokeDasharray="3,3" />
                </g>
              );
            })}

            {/* Draggable dots */}
            {x2.map((v, i) => {
              const sw = swish(v);
              const cx = xToSvg(v);
              const cy = yToSvg(sw);
              const isActive = activeIdx === i;
              return (
                <g key={'dot' + i}
                  onMouseDown={(e) => { e.preventDefault(); setDragging(i); }}
                  onTouchStart={(e) => { e.preventDefault(); setDragging(i); }}
                  onMouseEnter={() => setHovered(i)}
                  onMouseLeave={() => setHovered(null)}
                  style={{ cursor: 'grab' }}>
                  <circle cx={cx} cy={cy} r={isActive ? 14 : 10} fill={dimColors[i]} opacity={0.12} />
                  <circle cx={cx} cy={cy} r={isActive ? 7 : 5.5} fill={dimColors[i]}
                    stroke={isActive ? '#fff' : 'none'} strokeWidth={1.5} />
                  <text x={cx} y={cy - (i % 2 === 0 ? 12 : -6)}
                    textAnchor="middle" fontSize={9} fontWeight={600} fill={dimColors[i]}>
                    {dimLabels[i]}
                  </text>
                </g>
              );
            })}

            {/* Curve label */}
            <text x={xToSvg(4.5)} y={yToSvg(swish(4.5)) - 8}
              fontSize={9} fill={theme.colors.primary} opacity={0.7}>y = x * sig(x)</text>
          </svg>
        </div>

        {/* Computation Table */}
        <div style={{ background: theme.colors.surface, borderRadius: 8, padding: '8px 12px', marginBottom: 8 }}>
          {/* Header */}
          <div style={{
            display: 'grid', gridTemplateColumns: '26px 52px 14px 90px 14px 70px',
            alignItems: 'center', gap: '0 4px', marginBottom: 6,
            fontSize: 9, color: theme.colors.textMuted, textTransform: 'uppercase', letterSpacing: 0.5,
          }}>
            <span></span>
            <span style={{ textAlign: 'center' }}>x1 (signal)</span>
            <span style={{ textAlign: 'center' }}></span>
            <span style={{ textAlign: 'center' }}>Swish(x2) gate</span>
            <span style={{ textAlign: 'center' }}></span>
            <span style={{ textAlign: 'center' }}>output</span>
          </div>

          {results.map((r, i) => {
            const gateW = getGatePercent(r.swish);
            const isActive = activeIdx === i;
            const gateColor = dimColors[i];
            const outPositive = r.output >= 0;
            return (
              <div key={i} style={{
                display: 'grid', gridTemplateColumns: '26px 52px 14px 90px 14px 70px',
                alignItems: 'center', gap: '0 4px', marginBottom: 6,
                padding: '5px 4px', borderRadius: 5,
                background: isActive ? theme.colors.surfaceAlt : 'transparent',
                transition: 'background 0.2s',
              }}
                onMouseEnter={() => setHovered(i)}
                onMouseLeave={() => setHovered(null)}
              >
                {/* Dim label */}
                <div style={{
                  width: 20, height: 20, borderRadius: 4,
                  background: dimColors[i] + '22', color: dimColors[i],
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 10, fontWeight: 700,
                }}>{dimLabels[i]}</div>

                {/* x1 value with slider */}
                <div style={{ textAlign: 'center' }}>
                  <div style={{ fontSize: 13, fontWeight: 600, color: theme.colors.blue }}>
                    {r.x1.toFixed(1)}
                  </div>
                  <input type="range" min="-4" max="4" step="0.1" value={r.x1}
                    onChange={(e) => {
                      const val = parseFloat(e.target.value);
                      setX1(prev => prev.map((v, j) => j === i ? val : v));
                    }}
                    style={{ width: 48, height: 3, accentColor: theme.colors.blue, marginTop: 2 }}
                  />
                </div>

                {/* multiply */}
                <div style={{ fontSize: 11, color: theme.colors.textMuted, textAlign: 'center' }}>*</div>

                {/* Swish(x2) gate bar */}
                <div style={{ position: 'relative' }}>
                  <div style={{ fontSize: 11, fontWeight: 600, color: gateColor, marginBottom: 2 }}>
                    {r.swish >= 0 ? '+' : ''}{r.swish.toFixed(2)}
                  </div>
                  <div style={{
                    width: '100%', height: 6, borderRadius: 3,
                    background: theme.colors.surfaceAlt,
                    overflow: 'hidden',
                  }}>
                    <div style={{
                      width: gateW + '%',
                      height: '100%', borderRadius: 3,
                      background: gateColor,
                      opacity: 0.7,
                      transition: 'width 0.15s ease',
                    }} />
                  </div>
                  <div style={{ fontSize: 8, color: theme.colors.textMuted, marginTop: 1 }}>
                    sig={r.sigmoid.toFixed(2)}
                  </div>
                </div>

                {/* equals */}
                <div style={{ fontSize: 11, color: theme.colors.textMuted, textAlign: 'center' }}>=</div>

                {/* Output */}
                <div>
                  <div style={{
                    fontSize: 13, fontWeight: 700,
                    color: outPositive ? theme.colors.green : theme.colors.orange,
                    transition: 'color 0.2s',
                  }}>
                    {r.output >= 0 ? '+' : ''}{r.output.toFixed(2)}
                  </div>
                  <div style={{
                    width: '100%', height: 6, borderRadius: 3,
                    background: theme.colors.surfaceAlt,
                    overflow: 'hidden',
                    marginTop: 2,
                  }}>
                    <div style={{
                      width: Math.min(100, Math.abs(r.output) / Math.max(maxAbsOut, 0.5) * 100) + '%',
                      height: '100%', borderRadius: 3,
                      background: outPositive ? theme.colors.green : theme.colors.orange,
                      opacity: 0.7,
                      transition: 'width 0.15s ease',
                    }} />
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Formula */}
        <div style={{
          background: theme.colors.surfaceAlt, borderRadius: 6, padding: '6px 10px',
          fontSize: 10, color: theme.colors.textMuted, textAlign: 'center', marginBottom: 8,
          letterSpacing: 0.3,
        }}>
          SwiGLU(x) = x1 * Swish(x2) = x1 * (x2 * sigmoid(x2))
        </div>

        {/* Dynamic Insight */}
        <div style={{
          background: theme.colors.surface, borderRadius: 8, padding: '9px 14px',
          fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.5,
          borderLeft: '3px solid ' + (allBlocked ? theme.colors.orange : allOpen ? theme.colors.green : nearZero ? theme.colors.yellow : theme.colors.primary),
          transition: 'border-color 0.3s',
        }}>
          <span style={{
            color: allBlocked ? theme.colors.orange : allOpen ? theme.colors.green : nearZero ? theme.colors.yellow : theme.colors.primary,
            fontWeight: 600,
          }}>
            {allBlocked ? 'Blocked: ' : allOpen ? 'Open: ' : nearZero ? 'Soft gating: ' : activeIdx !== null ? dimLabels[activeIdx] + ': ' : 'Insight: '}
          </span>
          {allBlocked
            ? 'All gates are nearly closed! When x2 is very negative, sigmoid(x2) approaches 0, so Swish(x2) approaches 0 too. No signal from x1 passes through -- the network learns to silence these dimensions.'
            : allOpen
            ? 'All gates are wide open! When x2 is large and positive, sigmoid(x2) approaches 1, so Swish(x2) approaches x2 itself. x1 passes through scaled by x2 -- the network amplifies these dimensions.'
            : nearZero
            ? 'Near x2=0, the gate is partially open (Swish(0)=0). This is where the smooth Swish curve matters most -- unlike a hard gate (on/off), SwiGLU can do fractional gating, allowing fine-grained control over information flow.'
            : activeIdx !== null
            ? (() => {
              const r = results[activeIdx];
              if (Math.abs(r.swish) < 0.1) return 'Gate ' + dimLabels[activeIdx] + ' is nearly closed (Swish=' + r.swish.toFixed(2) + '). Signal x1=' + r.x1.toFixed(1) + ' is blocked regardless of its magnitude. This selective blocking is the GLU concept.';
              if (r.swish > 2) return 'Gate ' + dimLabels[activeIdx] + ' is wide open (Swish=' + r.swish.toFixed(2) + '). Signal x1=' + r.x1.toFixed(1) + ' passes through amplified. x2 acts as both gate AND amplifier -- the Swish property.';
              return 'Gate ' + dimLabels[activeIdx] + ': Swish(x2=' + r.x2.toFixed(1) + ') = ' + r.x2.toFixed(1) + ' * sig(' + r.x2.toFixed(1) + ') = ' + r.x2.toFixed(1) + ' * ' + r.sigmoid.toFixed(2) + ' = ' + r.swish.toFixed(2) + '. Output = ' + r.x1.toFixed(1) + ' * ' + r.swish.toFixed(2) + ' = ' + r.output.toFixed(2);
            })()
            : 'x2 controls the gate for each dimension of x1. Drag dots on the curve to see how different x2 values open/close gates. Some dimensions pass, others are blocked -- this selective gating is why SwiGLU powers LLaMA and PaLM.'
          }
        </div>
      </div>
    </div>
  );
}
